function calcInvestment() {
            const monthly = parseFloat(document.getElementById('monthlyInvestment').value);
            const years = parseFloat(document.getElementById('investYears').value);
            if (isNaN(monthly) || isNaN(years)) {
                alert('숫자를 입력해 주세요.');
                return;
